// Safely extract URL from body regardless of how n8n parses it
const item = $input.first();
const body = item.json;

// Handle both direct body and nested body shapes
const url = (
  body.url ||
  body.link ||
  body.body?.url ||
  ''
).toString().trim();

if (!url) {
  throw new Error('No URL found in request body. Send: {"url": "YOUR_LINK"}');
}

let platform = 'unknown';
if (url.includes('tidal.com'))                             platform = 'tidal';
else if (url.includes('qobuz.com'))                        platform = 'qobuz';
else if (url.includes('deezer.com'))                       platform = 'deezer';
else if (url.includes('spotify.com'))                      platform = 'spotify';
else if (url.includes('apple.com'))                        platform = 'apple';
else if (url.includes('soundcloud.com'))                   platform = 'soundcloud';
else if (url.includes('youtube.com') || url.includes('youtu.be')) platform = 'youtube';

const isLossless = ['tidal','qobuz','deezer'].includes(platform);

return [{
  json: {
    url,
    platform,
    quality: isLossless ? 'FLAC' : '320kbps'
  }
}];

// Get data from both upstream nodes
const lucidaRaw = $input.first().json;
const parsed    = $('Extract & Detect Platform').first().json;

// Dig through every known Lucida response shape
const downloadUrl =
  lucidaRaw?.url ||
  lucidaRaw?.result?.url ||
  lucidaRaw?.result?.download_url ||
  lucidaRaw?.download_url ||
  lucidaRaw?.data?.url ||
  null;

const meta =
  lucidaRaw?.result?.metadata ||
  lucidaRaw?.metadata ||
  lucidaRaw?.data?.metadata ||
  {};

const title  = meta.title  || lucidaRaw?.title  || lucidaRaw?.result?.title  || 'Unknown Title';
const artist = meta.artist || lucidaRaw?.artist || lucidaRaw?.result?.artist || '';

if (!downloadUrl) {
  return [{
    json: {
      status: 'error',
      message: 'Lucida could not find a download link for this URL.',
      platform: parsed.platform,
      quality:  parsed.quality,
      raw: lucidaRaw  // helps debug in n8n
    }
  }];
}

return [{
  json: {
    status:       'ok',
    platform:     parsed.platform,
    quality:      parsed.quality,
    download_url: downloadUrl,
    metadata: { title, artist }
  }
}];
